query:
{
  replicaSets(
    where: {     
      deploymentName: { eq: "" } 
      podTemplate: {
        OR: [
          {
            containersTemplates_SOME: {
              env_SOME: { isValueFromSet: { eq: true }, isSecretKeySelectorSet: { eq: true } }
            }
          }
          { NOT: { secretVolumes: { eq: [] } } }
        ]
      }
    }
  ) {
    ...AssetFragment
  }
}
